-- ============================================================================
-- 041_arith_questions_batch1.sql
-- Question-bank seed: Arithmetic chapters 1-3 (Number System; H.C.F. and
-- L.C.M. of Numbers; Decimal Fractions). 114 single-answer MCQs pulled from
-- ACTUAL previous-year papers of the exams students sit -- SBI/IBPS/RBI/Canara
-- PO & Clerk, SSC CGL/CHSL, TS/AP ICET, and IT placement (TCS NQT, Infosys,
-- Wipro, Cognizant) -- via IndiaBix, PrepInsta, Testbook PYQ, Adda247,
-- Oliveboard, CareerPower, Examveda, 2IIM, GeeksforGeeks, Sawaal.
--
-- The difficulty floor is exam-grade: even 'easy' is a real exam question
-- requiring genuine calculation (multi-number LCM, decimal HCF, least-number
-- to add/subtract, unit-digit cyclicity) -- NOT primary-school recall.
-- 'very_hard' reaches Fermat/Euler remainders, power towers, Legendre powers
-- and mixed recurring decimals. Every numeric answer was recomputed and
-- verified (modular pow, gcd/lcm, factorial powers, exact fractions); each
-- item has 4 distinct-valued options with exactly one correct.
--
-- Each question also carries a worked EXPLANATION (question.explanation) so
-- students can validate their answers on post-exam review.
--
-- Depends on 023 (Arithmetic subject + 35 chapters). Extends the idempotent
-- _seed_arith_q helper from 028 with an explanation arg (dollar-quoted text ->
-- no escaping). Safe to re-run.
-- ============================================================================

create or replace function public._seed_arith_q(p_chapter text, p_difficulty text, p_stem text, p_opts text[], p_correct int, p_explanation text) returns void language plpgsql as $$
declare v_subj uuid; v_chap uuid; v_qid uuid; i int;
begin
  select id into v_subj from public.subject where lower(name)='arithmetic' limit 1;
  if v_subj is null then raise exception 'Arithmetic subject not found (run 023 first)'; end if;
  select id into v_chap from public.chapter where subject_id=v_subj and lower(name)=lower(p_chapter) limit 1;
  if v_chap is null then raise exception 'Chapter % not found', p_chapter; end if;
  if exists (select 1 from public.question where chapter_id=v_chap and stem=p_stem) then return; end if;
  insert into public.question (subject_id, chapter_id, kind, difficulty, answer_type, stem, explanation)
  values (v_subj, v_chap, 'standard', p_difficulty, 'single', p_stem, p_explanation) returning id into v_qid;
  for i in 1..array_length(p_opts,1) loop
    insert into public.question_option (question_id, label, is_correct, position) values (v_qid, p_opts[i], i=p_correct, i-1);
  end loop;
end; $$;

-- Number System (39 questions)
select public._seed_arith_q($q$Number System$q$,'easy',$q$The least number that must be added to 2000 to make it exactly divisible by 45 is:$q$,array[$q$20$q$,$q$25$q$,$q$30$q$,$q$45$q$],2,$q$2000 ÷ 45 leaves remainder 20 (45×44=1980, 2000−1980=20). To reach the next multiple, add 45−20 = 25. Check: 2000+25 = 2025 = 45×45.$q$);
select public._seed_arith_q($q$Number System$q$,'easy',$q$What least number must be subtracted from 13601 so that the result is exactly divisible by 87?$q$,array[$q$23$q$,$q$29$q$,$q$31$q$,$q$37$q$],2,$q$13601 ÷ 87: 87×156 = 13572, remainder = 13601−13572 = 29. Subtract this remainder. Check: 13601−29 = 13572 = 87×156.$q$);
select public._seed_arith_q($q$Number System$q$,'easy',$q$Find the unit (last) digit of 795^95 − 358^58.$q$,array[$q$1$q$,$q$3$q$,$q$4$q$,$q$9$q$],1,$q$Any power of a number ending in 5 ends in 5, so 795^95 ends in 5. For 8: cycle is 8,4,2,6 (length 4); 58 mod 4 = 2, so 358^58 ends in the 2nd term = 4. Unit digit = 5 − 4 = 1.$q$);
select public._seed_arith_q($q$Number System$q$,'easy',$q$What is the unit digit of 4^372?$q$,array[$q$2$q$,$q$4$q$,$q$6$q$,$q$8$q$],3,$q$Powers of 4 cycle 4, 6, 4, 6 … : the exponent being even gives 6 and odd gives 4. 372 is even, so the unit digit is 6.$q$);
select public._seed_arith_q($q$Number System$q$,'easy',$q$What least number must be subtracted from 3000 to make it exactly divisible by 19?$q$,array[$q$11$q$,$q$15$q$,$q$17$q$,$q$19$q$],3,$q$3000 ÷ 19: 19×157 = 2983, remainder = 3000−2983 = 17. Subtract 17. Check: 3000−17 = 2983 = 19×157.$q$);
select public._seed_arith_q($q$Number System$q$,'easy',$q$How many zeros are there at the end of 100! (100 factorial)?$q$,array[$q$20$q$,$q$24$q$,$q$25$q$,$q$10$q$],2,$q$Trailing zeros come from factors of 5: ⌊100/5⌋ + ⌊100/25⌋ = 20 + 4 = 24 (factors of 2 are in surplus).$q$);
select public._seed_arith_q($q$Number System$q$,'easy',$q$What is the least number that must be added to 1056 to make it exactly divisible by 23?$q$,array[$q$2$q$,$q$3$q$,$q$18$q$,$q$21$q$],1,$q$1056 ÷ 23: 23×45 = 1035, remainder = 1056−1035 = 21. Add 23−21 = 2. Check: 1056+2 = 1058 = 23×46.$q$);
select public._seed_arith_q($q$Number System$q$,'easy',$q$What is the unit digit of 17^73?$q$,array[$q$1$q$,$q$3$q$,$q$7$q$,$q$9$q$],3,$q$Only the base's unit digit 7 matters. Powers of 7 cycle 7, 9, 3, 1 (length 4). 73 mod 4 = 1, so the unit digit equals the 1st term = 7.$q$);
select public._seed_arith_q($q$Number System$q$,'medium',$q$If the number 481*673 is completely divisible by 9, what is the digit in place of *?$q$,array[$q$5$q$,$q$6$q$,$q$7$q$,$q$8$q$],3,$q$Divisibility by 9 needs digit-sum divisible by 9. Known digits sum: 4+8+1+6+7+3 = 29. Need 29+* divisible by 9 → next multiple is 36 → * = 7.$q$);
select public._seed_arith_q($q$Number System$q$,'medium',$q$How many numbers between 200 and 600 are divisible by both 4 and 6?$q$,array[$q$30$q$,$q$32$q$,$q$33$q$,$q$34$q$],3,$q$Divisible by both 4 and 6 means divisible by LCM = 12. Multiples of 12 from 204 to 588: (588−204)/12 + 1 = 384/12 + 1 = 32 + 1 = 33.$q$);
select public._seed_arith_q($q$Number System$q$,'medium',$q$How many numbers from 1 to 100 (inclusive) are divisible by 2 or 3?$q$,array[$q$50$q$,$q$67$q$,$q$66$q$,$q$72$q$],2,$q$By inclusion–exclusion: divisible by 2 = 50, by 3 = 33, by 6 = 16. 50 + 33 − 16 = 67.$q$);
select public._seed_arith_q($q$Number System$q$,'medium',$q$If the 5-digit number 653*0 is exactly divisible by 80, what is the digit in place of *?$q$,array[$q$4$q$,$q$6$q$,$q$8$q$,$q$2$q$],2,$q$80 = 16 × 5. The last digit 0 handles divisibility by 5. For 16, test 653*0: only *=6 gives 65360 = 80×817. Check: 65360 ÷ 80 = 817 exactly.$q$);
select public._seed_arith_q($q$Number System$q$,'medium',$q$A number when divided by 342 gives a remainder 47. When the same number is divided by 19, the remainder is:$q$,array[$q$5$q$,$q$9$q$,$q$7$q$,$q$0$q$],2,$q$342 = 19 × 18, so 342 is a multiple of 19; the number = 342k + 47. Remainder mod 19 = 47 mod 19 = 47 − 38 = 9.$q$);
select public._seed_arith_q($q$Number System$q$,'medium',$q$Find the largest number which divides 964, 1238 and 1400 leaving remainders 41, 31 and 51 respectively.$q$,array[$q$61$q$,$q$71$q$,$q$81$q$,$q$91$q$],2,$q$Subtract remainders: 964−41=923, 1238−31=1207, 1400−51=1349. Required number = HCF(923,1207,1349) = 71.$q$);
select public._seed_arith_q($q$Number System$q$,'medium',$q$Find the sum of all two-digit numbers divisible by 7.$q$,array[$q$728$q$,$q$735$q$,$q$742$q$,$q$749$q$],1,$q$Two-digit multiples of 7: 14, 21, …, 98 — an AP with a=14, d=7, l=98, n=(98−14)/7+1=13. Sum = n(a+l)/2 = 13×(14+98)/2 = 13×56 = 728.$q$);
select public._seed_arith_q($q$Number System$q$,'medium',$q$How many three-digit numbers are exactly divisible by 7?$q$,array[$q$126$q$,$q$127$q$,$q$128$q$,$q$129$q$],3,$q$Smallest 3-digit multiple of 7 = 105 (7×15); largest = 994 (7×142). Count = 142 − 15 + 1 = 128.$q$);
select public._seed_arith_q($q$Number System$q$,'medium',$q$A number when divided by 5 leaves remainder 3. When the square of the same number is divided by 5, the remainder is:$q$,array[$q$1$q$,$q$2$q$,$q$3$q$,$q$4$q$],4,$q$Number = 5k+3, so square ≡ 3² = 9 (mod 5) = 4. Remainder = 4.$q$);
select public._seed_arith_q($q$Number System$q$,'medium',$q$When a number is divided by 899 the remainder is 63. What is the remainder when the same number is divided by 29?$q$,array[$q$4$q$,$q$5$q$,$q$6$q$,$q$7$q$],2,$q$899 = 29 × 31, so 899 is a multiple of 29; number = 899k + 63. Remainder mod 29 = 63 mod 29 = 63 − 58 = 5.$q$);
select public._seed_arith_q($q$Number System$q$,'hard',$q$What is the remainder when 2^256 is divided by 17?$q$,array[$q$1$q$,$q$2$q$,$q$4$q$,$q$16$q$],1,$q$By Fermat, 2^16 ≡ 1 (mod 17) since 17 is prime. Even simpler: 2^4 = 16 ≡ −1 (mod 17), so 2^8 ≡ 1. 256 = 8×32, so 2^256 = (2^8)^32 ≡ 1^32 = 1.$q$);
select public._seed_arith_q($q$Number System$q$,'hard',$q$Find the remainder when 15^40 is divided by 13.$q$,array[$q$1$q$,$q$2$q$,$q$3$q$,$q$4$q$],3,$q$15 ≡ 2 (mod 13), so we need 2^40 mod 13. Fermat: 2^12 ≡ 1 (mod 13). 40 = 12×3 + 4, so 2^40 ≡ 2^4 = 16 ≡ 3 (mod 13).$q$);
select public._seed_arith_q($q$Number System$q$,'hard',$q$How many factors (divisors) does 3600 have?$q$,array[$q$36$q$,$q$42$q$,$q$45$q$,$q$48$q$],3,$q$3600 = 2^4 × 3^2 × 5^2. Number of divisors = (4+1)(2+1)(2+1) = 5×3×3 = 45.$q$);
select public._seed_arith_q($q$Number System$q$,'hard',$q$What is the sum of all the factors of 360?$q$,array[$q$1170$q$,$q$1092$q$,$q$1080$q$,$q$1260$q$],1,$q$360 = 2^3 × 3^2 × 5. Sum of divisors = (2^4−1)/(2−1) × (3^3−1)/(3−1) × (5^2−1)/(5−1) = 15 × 13 × 6 = 1170.$q$);
select public._seed_arith_q($q$Number System$q$,'hard',$q$Find the remainder when 5^100 is divided by 18.$q$,array[$q$7$q$,$q$11$q$,$q$13$q$,$q$17$q$],3,$q$5^1=5, 5^2=25≡7, 5^3≡35≡17≡−1 (mod 18). So 5^3 ≡ −1, giving 5^6 ≡ 1. 100 = 6×16 + 4, so 5^100 ≡ 5^4 = 5·5^3 ≡ 5·(−1) = −5 ≡ 13 (mod 18).$q$);
select public._seed_arith_q($q$Number System$q$,'hard',$q$What is the highest power of 3 contained in 100! (100 factorial)?$q$,array[$q$33$q$,$q$48$q$,$q$44$q$,$q$50$q$],2,$q$Legendre's formula: ⌊100/3⌋ + ⌊100/9⌋ + ⌊100/27⌋ + ⌊100/81⌋ = 33 + 11 + 3 + 1 = 48.$q$);
select public._seed_arith_q($q$Number System$q$,'hard',$q$What are the last two digits of 7^2008?$q$,array[$q$01$q$,$q$07$q$,$q$43$q$,$q$49$q$],1,$q$Work mod 100. 7^4 = 2401 ≡ 1 (mod 100). 2008 = 4×502, so 7^2008 = (7^4)^502 ≡ 1^502 = 01.$q$);
select public._seed_arith_q($q$Number System$q$,'hard',$q$Find the remainder when 39^12 is divided by 7.$q$,array[$q$1$q$,$q$2$q$,$q$4$q$,$q$5$q$],1,$q$39 ≡ 4 (mod 7), so need 4^12 mod 7. 4^3 = 64 ≡ 1 (mod 7). 12 = 3×4, so 4^12 = (4^3)^4 ≡ 1. Remainder = 1.$q$);
select public._seed_arith_q($q$Number System$q$,'hard',$q$How many trailing zeros does 150! (150 factorial) have?$q$,array[$q$30$q$,$q$34$q$,$q$37$q$,$q$62$q$],3,$q$Count factors of 5: ⌊150/5⌋ + ⌊150/25⌋ + ⌊150/125⌋ = 30 + 6 + 1 = 37.$q$);
select public._seed_arith_q($q$Number System$q$,'hard',$q$How many factors of 3600 are perfect squares?$q$,array[$q$8$q$,$q$9$q$,$q$12$q$,$q$15$q$],3,$q$3600 = 2^4 × 3^2 × 5^2. A perfect-square factor needs even exponents. Choices: for 2 → {0,2,4}=3, for 3 → {0,2}=2, for 5 → {0,2}=2. Total = 3×2×2 = 12.$q$);
select public._seed_arith_q($q$Number System$q$,'very_hard',$q$What is the remainder when 3^101 is divided by 5?$q$,array[$q$1$q$,$q$2$q$,$q$3$q$,$q$4$q$],3,$q$By Fermat, 3^4 ≡ 1 (mod 5). 101 = 4×25 + 1, so 3^101 ≡ 3^1 = 3 (mod 5).$q$);
select public._seed_arith_q($q$Number System$q$,'very_hard',$q$Find the remainder when 17^200 is divided by 18.$q$,array[$q$1$q$,$q$5$q$,$q$13$q$,$q$17$q$],1,$q$17 ≡ −1 (mod 18). So 17^200 ≡ (−1)^200 = 1 (mod 18) since the exponent is even.$q$);
select public._seed_arith_q($q$Number System$q$,'very_hard',$q$What is the highest power of 12 that divides 100! (100 factorial)?$q$,array[$q$32$q$,$q$44$q$,$q$48$q$,$q$97$q$],3,$q$12 = 2^2 × 3. Power of 2 in 100! = 50+25+12+6+3+1 = 97 → gives ⌊97/2⌋ = 48 pairs. Power of 3 = 33+11+3+1 = 48. Limiting factor = min(48, 48) = 48.$q$);
select public._seed_arith_q($q$Number System$q$,'very_hard',$q$What is the remainder when 32^(32^32) is divided by 9?$q$,array[$q$1$q$,$q$4$q$,$q$5$q$,$q$7$q$],2,$q$32 ≡ 5 (mod 9). Powers of 5 mod 9 cycle with length 6 (5,7,8,4,2,1). Need exponent 32^32 mod 6: 32 ≡ 2 (mod 6), and 2^n mod 6 = 4 for even n≥2, so 32^32 ≡ 4 (mod 6). Thus 5^4 mod 9 = 625 mod 9 = 4.$q$);
select public._seed_arith_q($q$Number System$q$,'very_hard',$q$The number 2^32 + 1 is exactly divisible by which of the following?$q$,array[$q$257$q$,$q$321$q$,$q$641$q$,$q$769$q$],3,$q$This is the famous Fermat-number result (Euler): 2^32 + 1 = 4294967297 = 641 × 6700417. So it is divisible by 641. (2^32+1) mod 641 = 0.$q$);
select public._seed_arith_q($q$Number System$q$,'very_hard',$q$What is the unit digit of 7^(7^7)?$q$,array[$q$1$q$,$q$3$q$,$q$7$q$,$q$9$q$],2,$q$Unit digit of powers of 7 cycles 7,9,3,1 (length 4). Need exponent 7^7 mod 4: 7 ≡ 3 ≡ −1 (mod 4), and 7^7 has odd exponent so ≡ −1 ≡ 3 (mod 4). The 3rd term of the cycle is 3.$q$);
select public._seed_arith_q($q$Number System$q$,'very_hard',$q$Find the remainder when 25^25 is divided by 26.$q$,array[$q$1$q$,$q$24$q$,$q$25$q$,$q$0$q$],3,$q$25 ≡ −1 (mod 26). So 25^25 ≡ (−1)^25 = −1 ≡ 25 (mod 26), since the exponent is odd.$q$);
select public._seed_arith_q($q$Number System$q$,'very_hard',$q$Find the greatest number which divides 1657 and 2037 leaving remainders 6 and 5 respectively.$q$,array[$q$123$q$,$q$127$q$,$q$235$q$,$q$305$q$],2,$q$Subtract the remainders: 1657−6 = 1651, 2037−5 = 2032. Required number = HCF(1651, 2032). 2032 = 1651×1 + 381; 1651 = 381×4 + 127; 381 = 127×3 + 0 → HCF = 127.$q$);
select public._seed_arith_q($q$Number System$q$,'very_hard',$q$What is the remainder when 3^100 is divided by 7?$q$,array[$q$1$q$,$q$2$q$,$q$4$q$,$q$5$q$],3,$q$Fermat: 3^6 ≡ 1 (mod 7). 100 = 6×16 + 4, so 3^100 ≡ 3^4 = 81 ≡ 81 − 77 = 4 (mod 7).$q$);
select public._seed_arith_q($q$Number System$q$,'very_hard',$q$Find the smallest number which when divided by 5, 6 and 7 leaves a remainder 4 in each case.$q$,array[$q$144$q$,$q$184$q$,$q$214$q$,$q$244$q$],3,$q$Same remainder in each case → number = LCM(5,6,7)×k + 4 = 210k + 4. Smallest positive (k=1) = 214. Check: 214 = 210+4, and 214 mod 5 = 4, mod 6 = 4, mod 7 = 4.$q$);
select public._seed_arith_q($q$Number System$q$,'very_hard',$q$What are the last two digits of 2^1000?$q$,array[$q$24$q$,$q$36$q$,$q$52$q$,$q$76$q$],4,$q$Powers of 2 mod 100 become periodic with cycle length 20 from 2^2 onward. 1000 ≡ 0 (mod 20) maps to the same class as 2^20, whose last two digits are 76. Hence 2^1000 ends in 76.$q$);

-- H.C.F. and L.C.M. of Numbers (38 questions)
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'easy',$q$Find the L.C.M. of 22, 54, 108, 135 and 198.$q$,array[$q$2970$q$,$q$5940$q$,$q$11880$q$,$q$1980$q$],2,$q$22=2·11, 54=2·3³, 108=2²·3³, 135=3³·5, 198=2·3²·11. LCM = 2²·3³·5·11 = 4·27·5·11 = 5940.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'easy',$q$Find the H.C.F. of 1.75, 5.6 and 7.$q$,array[$q$0.35$q$,$q$0.7$q$,$q$0.175$q$,$q$1.75$q$],1,$q$Make equal decimals: 1.75, 5.60, 7.00 → multiply by 100 → 175, 560, 700. HCF(175,560,700)=35. So HCF = 0.35.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'easy',$q$The greatest length that can exactly measure 700 cm, 385 cm and 1295 cm is:$q$,array[$q$25 cm$q$,$q$35 cm$q$,$q$45 cm$q$,$q$55 cm$q$],2,$q$Greatest exact measure = HCF. 700=2²·5²·7, 385=5·7·11, 1295=5·7·37. Common = 5·7 = 35 cm.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'easy',$q$The least number which is exactly divisible by 15, 20, 24, 32 and 36 is:$q$,array[$q$1440$q$,$q$2880$q$,$q$720$q$,$q$1200$q$],1,$q$Least such number = LCM. 15=3·5, 20=2²·5, 24=2³·3, 32=2⁵, 36=2²·3². LCM = 2⁵·3²·5 = 32·9·5 = 1440.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'easy',$q$Find the H.C.F. of the fractions 2/3, 8/9, 64/81 and 10/27.$q$,array[$q$2/81$q$,$q$2/3$q$,$q$4/27$q$,$q$2/27$q$],1,$q$HCF of fractions = HCF(numerators)/LCM(denominators). HCF(2,8,64,10)=2; LCM(3,9,81,27)=81. Answer = 2/81.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'easy',$q$Find the L.C.M. of the fractions 3/4, 5/6 and 7/15.$q$,array[$q$105$q$,$q$35$q$,$q$210$q$,$q$1/60$q$],1,$q$LCM of fractions = LCM(numerators)/HCF(denominators). LCM(3,5,7)=105; HCF(4,6,15)=1. Answer = 105/1 = 105.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'easy',$q$The greatest four-digit number which is exactly divisible by 15, 25, 40 and 75 is:$q$,array[$q$9000$q$,$q$9400$q$,$q$9600$q$,$q$9800$q$],3,$q$LCM(15,25,40,75): 15=3·5, 25=5², 40=2³·5, 75=3·5² → LCM = 2³·3·5² = 600. Greatest 4-digit multiple of 600 = 9999÷600 = 16 (rem 399) → 16·600 = 9600.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'easy',$q$Find the smallest number which is exactly divisible by 8, 9, 10, 15 and 20.$q$,array[$q$180$q$,$q$240$q$,$q$360$q$,$q$720$q$],3,$q$LCM: 8=2³, 9=3², 10=2·5, 15=3·5, 20=2²·5. LCM = 2³·3²·5 = 8·9·5 = 360.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'easy',$q$Find the H.C.F. of 0.63, 1.05 and 2.1.$q$,array[$q$0.07$q$,$q$0.21$q$,$q$0.35$q$,$q$0.63$q$],2,$q$Equalise decimals to 0.63, 1.05, 2.10 → ×100 → 63, 105, 210. HCF: 63=3²·7, 105=3·5·7, 210=2·3·5·7 → common 3·7 = 21. So HCF = 0.21.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'easy',$q$The least five-digit number which is exactly divisible by 12, 15, 20 and 54 is:$q$,array[$q$10260$q$,$q$10800$q$,$q$10020$q$,$q$10120$q$],1,$q$LCM(12,15,20,54): 12=2²·3, 15=3·5, 20=2²·5, 54=2·3³ → LCM = 2²·3³·5 = 540. Smallest 5-digit multiple: 10000÷540 = 18.5 → 19·540 = 10260.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'medium',$q$The product of two numbers is 2028 and their H.C.F. is 13. The number of such pairs is:$q$,array[$q$1$q$,$q$2$q$,$q$3$q$,$q$4$q$],2,$q$Let numbers = 13a, 13b with a,b coprime. Product = 169ab = 2028 → ab = 12. Coprime pairs (a,b) with ab=12: (1,12) and (3,4). [(2,6),(4,3 dup)] not coprime. So 2 pairs.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'medium',$q$The H.C.F. and L.C.M. of two numbers are 11 and 693 respectively. If one number is 77, the other is:$q$,array[$q$66$q$,$q$88$q$,$q$99$q$,$q$110$q$],3,$q$Product of numbers = HCF × LCM = 11 × 693 = 7623. Other number = 7623 ÷ 77 = 99.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'medium',$q$Two numbers are in the ratio 3 : 4 and their H.C.F. is 4. Their L.C.M. is:$q$,array[$q$12$q$,$q$16$q$,$q$24$q$,$q$48$q$],4,$q$Numbers = 3×4 and 4×4 = 12 and 16. LCM(12,16) = 48.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'medium',$q$The H.C.F. of two numbers is 23 and the other two factors of their L.C.M. are 13 and 14. The larger of the two numbers is:$q$,array[$q$276$q$,$q$299$q$,$q$322$q$,$q$345$q$],3,$q$Numbers are 23×13 = 299 and 23×14 = 322. Larger = 322.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'medium',$q$The sum of two numbers is 216 and their H.C.F. is 27. How many such pairs of numbers are possible?$q$,array[$q$1$q$,$q$2$q$,$q$3$q$,$q$4$q$],2,$q$Numbers = 27a, 27b, a,b coprime. 27a+27b=216 → a+b=8. Coprime pairs summing to 8: (1,7),(3,5). [(2,6),(4,4) not coprime]. So 2 pairs.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'medium',$q$The greatest three-digit number exactly divisible by 6, 9 and 12 is:$q$,array[$q$936$q$,$q$960$q$,$q$972$q$,$q$996$q$],3,$q$LCM(6,9,12) = 36. Greatest 3-digit multiple: 999÷36 = 27 rem 27 → 27×36 = 972.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'medium',$q$Find the H.C.F. of the fractions 9/10, 12/25, 18/35 and 21/40.$q$,array[$q$3/1400$q$,$q$3/700$q$,$q$9/1400$q$,$q$1/1400$q$],1,$q$HCF of fractions = HCF(numerators)/LCM(denominators). HCF(9,12,18,21)=3; LCM(10,25,35,40): 10=2·5,25=5²,35=5·7,40=2³·5 → 2³·5²·7 = 1400. Answer = 3/1400.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'medium',$q$The H.C.F. and L.C.M. of two numbers are 6 and 36 respectively. If one number is 12, the other number is:$q$,array[$q$18$q$,$q$24$q$,$q$30$q$,$q$6$q$],1,$q$Product = HCF×LCM = 6×36 = 216. Other = 216 ÷ 12 = 18. (Check: HCF(12,18)=6, LCM=36 ✓.)$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'medium',$q$The L.C.M. of two numbers is 48 and the numbers are in the ratio 2 : 3. The sum of the two numbers is:$q$,array[$q$28$q$,$q$32$q$,$q$40$q$,$q$64$q$],3,$q$Numbers = 2x, 3x (coprime multipliers) → HCF = x, LCM = 6x = 48 → x = 8. Numbers 16 and 24; sum = 40.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'hard',$q$Six bells commence tolling together and toll at intervals of 2, 4, 6, 8, 10 and 12 seconds respectively. In 30 minutes, how many times do they toll together?$q$,array[$q$4$q$,$q$10$q$,$q$15$q$,$q$16$q$],4,$q$LCM(2,4,6,8,10,12) = 120 s = 2 min. In 30 min they coincide every 2 min → 30÷2 = 15 times, plus the initial toll at start = 16 times.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'hard',$q$Find the greatest number that will divide 43, 91 and 183 so as to leave the same remainder in each case.$q$,array[$q$4$q$,$q$7$q$,$q$9$q$,$q$13$q$],1,$q$Required number = HCF of the differences: (91−43)=48, (183−91)=92, (183−43)=140. HCF(48,92,140) = 4.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'hard',$q$Three traffic lights change after every 48, 72 and 108 seconds respectively. If they change simultaneously at 8:00:00 hrs, at what time will they next change together?$q$,array[$q$8:07:12 hrs$q$,$q$8:07:24 hrs$q$,$q$8:07:00 hrs$q$,$q$8:09:12 hrs$q$],1,$q$LCM(48,72,108): 48=2⁴·3, 72=2³·3², 108=2²·3³ → 2⁴·3³ = 432 s = 7 min 12 s. Next together at 8:00:00 + 7:12 = 8:07:12.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'hard',$q$What is the largest size of square tiles that can be used to pave the floor of a room 15 m 17 cm long and 9 m 2 cm broad?$q$,array[$q$41 cm$q$,$q$37 cm$q$,$q$43 cm$q$,$q$29 cm$q$],1,$q$Convert to cm: 1517 and 902. Largest square tile side = HCF(1517,902). 1517=41×37, 902=41×22 → HCF = 41 cm.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'hard',$q$A rectangular floor 15 m 17 cm long and 9 m 2 cm broad is to be paved with equal square tiles of the largest possible size. The number of tiles required is:$q$,array[$q$814$q$,$q$806$q$,$q$900$q$,$q$792$q$],1,$q$Largest tile side = HCF(1517,902) = 41 cm. Tiles = (1517÷41)×(902÷41) = 37×22 = 814.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'hard',$q$Find the greatest number which divides 2011 and 2623, leaving remainders 9 and 5 respectively.$q$,array[$q$154$q$,$q$144$q$,$q$134$q$,$q$164$q$],1,$q$Subtract remainders: 2011−9 = 2002, 2623−5 = 2618. Required = HCF(2002,2618). 2002=2·7·11·13, 2618=2·7·11·17 → HCF = 2·7·11 = 154.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'hard',$q$The greatest number that divides 124, 190 and 401 leaving remainders 5, 3 and 10 respectively is:$q$,array[$q$11$q$,$q$13$q$,$q$17$q$,$q$19$q$],3,$q$Subtract remainders: 124−5=119, 190−3=187, 401−10=391. HCF(119,187,391): 119=7·17, 187=11·17, 391=17·23 → HCF = 17.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'hard',$q$Four runners start together and take 200, 300, 360 and 450 seconds respectively to complete one round of a circular track. After how many seconds will they all be together at the starting point again?$q$,array[$q$1800$q$,$q$900$q$,$q$3600$q$,$q$1200$q$],1,$q$They meet at the start after LCM of the lap times. LCM(200,300,360,450): 200=2³·5², 300=2²·3·5², 360=2³·3²·5, 450=2·3²·5² → 2³·3²·5² = 1800 s.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'hard',$q$Let N be the greatest number that will divide 1305, 4665 and 6905, leaving the same remainder in each case. Then the sum of the digits in N is:$q$,array[$q$4$q$,$q$5$q$,$q$6$q$,$q$8$q$],1,$q$N = HCF of differences: (4665−1305)=3360, (6905−4665)=2240, (6905−1305)=5600. HCF(3360,2240,5600) = 1120. Digit sum = 1+1+2+0 = 4.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'very_hard',$q$Find the least number which, when divided by 6, 7, 8, 9 and 12, leaves a remainder 5 in each case.$q$,array[$q$509$q$,$q$504$q$,$q$499$q$,$q$512$q$],1,$q$LCM(6,7,8,9,12): 8=2³, 9=3², 7, 12=2²·3 → 2³·3²·7 = 504. Required = LCM + 5 = 509.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'very_hard',$q$Find the least multiple of 7 which, when divided by 6, 9, 15 and 18, leaves the remainder 4 in each case.$q$,array[$q$364$q$,$q$350$q$,$q$368$q$,$q$378$q$],1,$q$LCM(6,9,15,18) = 90, so numbers are of form 90k+4. Need divisible by 7: 94,184,274,364… 364 = 7×52 ✓ (364÷90 = 4 r 4). Least = 364.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'very_hard',$q$Find the least number which, when divided by 5, 6, 7 and 8, leaves a remainder 3, but when divided by 9 leaves no remainder.$q$,array[$q$1683$q$,$q$1443$q$,$q$1523$q$,$q$1263$q$],1,$q$LCM(5,6,7,8) = 840, so numbers are 840k+3. Need divisible by 9: k=1→843 (8+4+3=15, no), k=2→1683 (1+6+8+3=18 → ÷9 ✓). Least = 1683.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'very_hard',$q$Find the greatest four-digit number which, when divided by 4, 7 and 13, leaves a remainder 3 in each case.$q$,array[$q$9831$q$,$q$9828$q$,$q$9855$q$,$q$9464$q$],1,$q$LCM(4,7,13) = 364. Numbers = 364k+3. Greatest 4-digit: (9999−3)=9996, 9996÷364 = 27 rem 168 → 27×364 = 9828, +3 = 9831.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'very_hard',$q$Three numbers are mutually co-prime. The product of the first two is 551 and the product of the last two is 1073. The sum of the three numbers is:$q$,array[$q$75$q$,$q$81$q$,$q$85$q$,$q$89$q$],3,$q$551 = 19×29, 1073 = 29×37. Common factor 29 is the middle number; the three are 19, 29, 37. Sum = 19+29+37 = 85.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'very_hard',$q$Find the least number which, when divided by 20, 25, 35 and 40, leaves remainders 14, 19, 29 and 34 respectively.$q$,array[$q$1394$q$,$q$1400$q$,$q$1386$q$,$q$1406$q$],1,$q$In each case (divisor − remainder) = 6, a constant. So required = LCM(20,25,35,40) − 6. LCM: 20=2²·5, 25=5², 35=5·7, 40=2³·5 → 2³·5²·7 = 1400. Answer = 1400 − 6 = 1394.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'very_hard',$q$Find the least number which, when divided by 4, 5 and 6, leaves remainders 1, 2 and 3 respectively.$q$,array[$q$57$q$,$q$60$q$,$q$54$q$,$q$63$q$],1,$q$Each (divisor − remainder) = 3, constant. Required = LCM(4,5,6) − 3 = 60 − 3 = 57. Check: 57÷4=14 r1, 57÷5=11 r2, 57÷6=9 r3 ✓.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'very_hard',$q$The H.C.F. and L.C.M. of two numbers are 16 and 160 respectively. If one of the numbers is 32, the other number is:$q$,array[$q$48$q$,$q$80$q$,$q$96$q$,$q$112$q$],2,$q$Product = HCF×LCM = 16×160 = 2560. Other = 2560 ÷ 32 = 80. (Check: HCF(32,80)=16, LCM=160 ✓.)$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'very_hard',$q$Find the largest number which divides 62, 132 and 237 leaving the same remainder in each case.$q$,array[$q$25$q$,$q$35$q$,$q$30$q$,$q$45$q$],2,$q$Required = HCF of differences: (132−62)=70, (237−132)=105, (237−62)=175. HCF(70,105,175): 70=2·5·7, 105=3·5·7, 175=5²·7 → 5·7 = 35.$q$);
select public._seed_arith_q($q$H.C.F. and L.C.M. of Numbers$q$,'very_hard',$q$Five bells begin to toll together and toll at intervals of 6, 7, 8, 9 and 12 seconds respectively. In one hour, how many times do they toll together (including the start)?$q$,array[$q$8$q$,$q$7$q$,$q$9$q$,$q$6$q$],1,$q$LCM(6,7,8,9,12): 8=2³, 9=3², 7, 12=2²·3 → 2³·3²·7 = 504 s. In 3600 s they coincide every 504 s: 3600÷504 = 7 (rem 72) → 7 times after start + 1 initial = 8 times.$q$);

-- Decimal Fractions (37 questions)
select public._seed_arith_q($q$Decimal Fractions$q$,'easy',$q$Simplify: (0.03 × 0.03 − 0.02 × 0.02) ÷ (0.03 + 0.02)$q$,array[$q$0.005$q$,$q$0.01$q$,$q$0.05$q$,$q$0.1$q$],2,$q$Numerator is a²−b² with a=0.03, b=0.02 = (a+b)(a−b) = (0.05)(0.01). Divide by (a+b)=0.05, leaving (a−b)=0.01.$q$);
select public._seed_arith_q($q$Decimal Fractions$q$,'easy',$q$Evaluate: [(2.39)² − (1.61)²] ÷ (2.39 − 1.61)$q$,array[$q$2$q$,$q$4$q$,$q$6$q$,$q$8$q$],2,$q$(a²−b²)/(a−b) = a+b = 2.39 + 1.61 = 4.$q$);
select public._seed_arith_q($q$Decimal Fractions$q$,'easy',$q$Simplify: (3.6 × 0.48 × 2.50) ÷ (0.12 × 0.09 × 0.5)$q$,array[$q$800$q$,$q$80$q$,$q$2000$q$,$q$920$q$],1,$q$Numerator = 3.6×0.48×2.50 = 4.32. Denominator = 0.12×0.09×0.5 = 0.0054. 4.32 ÷ 0.0054 = 800.$q$);
select public._seed_arith_q($q$Decimal Fractions$q$,'easy',$q$If 144 ÷ 0.144 = 1000 ÷ x, then the value of x is:$q$,array[$q$1$q$,$q$10$q$,$q$0.1$q$,$q$0.01$q$],1,$q$144 ÷ 0.144 = 144000/144 = 1000. So 1000 = 1000/x ⇒ x = 1.$q$);
