select public._seed_arith_q($q$Decimal Fractions$q$,'easy',$q$Simplify: (0.1³ + 0.02³) ÷ (0.2³ + 0.04³)$q$,array[$q$1/8$q$,$q$1/4$q$,$q$1/2$q$,$q$1/16$q$],1,$q$Denominator terms are exactly double the numerator terms (0.2=2×0.1, 0.04=2×0.02); cubing scales by 2³=8, so the ratio = 1/8 = 0.125.$q$);
