select public._seed_arith_q($q$Decimal Fractions$q$,'medium',$q$Arrange in ascending order and pick the greatest: 7/8, 0.87, 5/6, 0.84$q$,array[$q$0.87$q$,$q$7/8$q$,$q$5/6$q$,$q$0.84$q$],2,$q$As decimals: 7/8=0.875, 5/6≈0.833, 0.87, 0.84. Ascending: 5/6 < 0.84 < 0.87 < 7/8. Greatest = 7/8.$q$);
