select public._seed_arith_q($q$Decimal Fractions$q$,'hard',$q$Express 0.16̄ (0.1666…, only the 6 repeats) as a fraction in lowest terms.$q$,array[$q$1/6$q$,$q$16/99$q$,$q$15/99$q$,$q$8/45$q$],1,$q$Mixed recurring: (whole after point − non-repeating part)/(9 for each repeating digit, 0 for each non-repeating) = (16 − 1)/90 = 15/90 = 1/6.$q$);
