select public._seed_arith_q($q$Decimal Fractions$q$,'hard',$q$Find the value of [(0.98)³ − (0.02)³] ÷ [(0.98)² + 0.98×0.02 + (0.02)²]$q$,array[$q$0.96$q$,$q$0.98$q$,$q$1$q$,$q$0.94$q$],1,$q$(a³−b³)/(a²+ab+b²) = a−b = 0.98 − 0.02 = 0.96.$q$);
