select public._seed_arith_q($q$Decimal Fractions$q$,'very_hard',$q$What is the value of 3 − 0.9̄ (where 0.9̄ = 0.9999…) ?$q$,array[$q$2$q$,$q$2.1$q$,$q$2.0001$q$,$q$2.1̄$q$],1,$q$The identity 0.9̄ = 1 (since 0.9̄ = 9/9 = 1). So 3 − 0.9̄ = 3 − 1 = 2.$q$);
select public._seed_arith_q($q$Decimal Fractions$q$,'very_hard',$q$Find the value of 0.6̄ + 0.7̄ + 0.8̄ (all single-digit recurring).$q$,array[$q$7/3$q$,$q$5/2$q$,$q$2.1$q$,$q$2.3̄$q$],1,$q$Each 0.d̄ = d/9. Sum = (6+7+8)/9 = 21/9 = 7/3 ≈ 2.333…$q$);
select public._seed_arith_q($q$Decimal Fractions$q$,'very_hard',$q$Find the value of 0.1̄6̄ + 0.8̄3̄ (both 2-digit recurring).$q$,array[$q$1$q$,$q$0.99$q$,$q$0.9̄$q$,$q$50/99$q$],1,$q$0.1̄6̄ = 16/99 and 0.8̄3̄ = 83/99. Sum = (16+83)/99 = 99/99 = 1.$q$);
select public._seed_arith_q($q$Decimal Fractions$q$,'very_hard',$q$Find the value of (0.3̄)² (the square of 0.3333…).$q$,array[$q$1/9$q$,$q$0.9̄$q$,$q$1/6$q$,$q$2/9$q$],1,$q$0.3̄ = 3/9 = 1/3. (1/3)² = 1/9 (which equals 0.1̄).$q$);
select public._seed_arith_q($q$Decimal Fractions$q$,'very_hard',$q$Find the value of 0.6̄ × 0.6̄ (product of two recurring decimals).$q$,array[$q$4/9$q$,$q$0.36$q$,$q$0.3̄6̄$q$,$q$9/25$q$],1,$q$0.6̄ = 2/3. (2/3)² = 4/9 (= 0.4̄). The naive answer 0.36 is a distractor trap.$q$);
select public._seed_arith_q($q$Decimal Fractions$q$,'very_hard',$q$Express 5.218̄ (5.2181818…, only '18' repeats) as a fraction in lowest terms.$q$,array[$q$287/55$q$,$q$5218/990$q$,$q$216/990$q$,$q$287/50$q$],1,$q$Repeating block after '5.2' is '18'. Fraction = (5218 − 52)/990 = 5166/990 = 287/55. Check: 287/55 = 5.2181818…$q$);
select public._seed_arith_q($q$Decimal Fractions$q$,'very_hard',$q$Find the value of (0.3̄ + 0.6̄) ÷ 0.9̄.$q$,array[$q$1$q$,$q$0.9$q$,$q$1.1̄$q$,$q$0.99$q$],1,$q$0.3̄ + 0.6̄ = 1/3 + 2/3 = 1, and 0.9̄ = 1. So 1 ÷ 1 = 1.$q$);
select public._seed_arith_q($q$Decimal Fractions$q$,'very_hard',$q$Express 0.5̄4̄ (0.545454…) as a fraction in lowest terms.$q$,array[$q$6/11$q$,$q$5/9$q$,$q$54/100$q$,$q$3/5$q$],1,$q$0.5̄4̄ = 54/99. Reduce by 9: 54/99 = 6/11. Check: 6/11 = 0.545454…$q$);
select public._seed_arith_q($q$Decimal Fractions$q$,'very_hard',$q$If x = 0.0̄3̄7̄ (0.037037037…), then the value of 1/x is:$q$,array[$q$27$q$,$q$37$q$,$q$270$q$,$q$2.7$q$],1,$q$x = 037/999 = 37/999. Since 999 = 27×37, x = 1/27. Therefore 1/x = 27.$q$);

